var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"어떻습니까?","JPN":"どうですか？","ENG":"So?","TWN":"怎麼樣？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"진실을 알고서 이면의 것들을 마주하게 된 소감은?","JPN":"真実を知って、裏世界の存在に向き合った感想は？","ENG":"How does it feel to know the truth and see what is on the other side?","TWN":"得知真相之後，面對異界事物的感想是什麼？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…네. 이제야 알겠어요.","JPN":"……はい。やっとわかりました。","ENG":"...Yes. I understand now.","TWN":"…是，我現在才明白。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 수많은 그림자들에게서 느낀 기시감은… 착각이 아니었군요.","JPN":"あの数えきれないシャドウたちから感じた既視感は……私の勘違いではなかった。","ENG":"The sense of deja vu I felt from those countless Shadows... I wasn't mistaken.","TWN":"從無數暗影身上感受到的既視感…原來不是錯覺。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이런 식으로… 옛 세계에 남겨진 전우들을 몇 번씩이고 제 손으로 죽이고 있었던 거네요.","JPN":"こうして私は……旧世界に残された戦友たちを、何度も手にかけてきたのですね。","ENG":"I've been killing the comrades left behind in the old world again and again, with my own hands...","TWN":"我曾經用這種方式…親手殺了好幾次留存在舊世界的那些戰友。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"왼쪽 팔이 없었던 그 그림자는… 부전대장 타티아나.","JPN":"左腕がなかったあのシャドウは……副戦隊長のタテイアナ。","ENG":"The Shadow that had no left arm... That was Deputy Commander Tatiana.","TWN":"那個沒有左手臂的暗影是…副隊長塔蒂亞娜。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"가시로 뒤덮인 목 없는 그림자는… 말더듬이 신병 나탈리아.","JPN":"いばらに覆われた首なしのシャドウは……新兵のナタリア。","ENG":"The headless Shadow covered in thorns... That was the stuttering recruit, Natalia.","TWN":"被荊棘覆蓋，沒有脖子的暗影是…口吃的新兵那塔利亞。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그리고 익숙한 대검을 휘두르던 외눈의 그림자는…","JPN":"そして、見慣れた大剣を振るっていた隻眼のシャドウは……","ENG":"And the one-eyed Shadow that wielded a familiar greatsword must have been...","TWN":"還有揮舞熟悉大劍的獨眼暗影…"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"시렌 전대를 창설했던 제 아버지… 펠릭스였겠죠.","JPN":"シレン戦隊の創設者、私の父親……フェリックスだったのでしょう。","ENG":"...my father and founder of the Sirin Division... Felix.","TWN":"應該是我創立賽蓮戰隊的父親…緋莉克絲吧。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이제 말해줘요, 삼하인.","JPN":"教えてください、サウィン。","ENG":"Now, tell me, Samhain.","TWN":"現在就告訴我吧，薩溫。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신이 나에게서 원했던 건… 고작 내 영혼 하나가 아닌 거죠?","JPN":"あなたが私に求めていたのは……私の魂だけではない、そうでしょう？","ENG":"What you wanted from me... it wasn't just my soul, was it?","TWN":"你想從我身上得到的東西…不只是我的靈魂吧？"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"제가 원하는 건 당신이 모든 기억을 간직한 채, 계속해서 미래로 나아가는 겁니다.","JPN":"私の望みは、あなたがすべての記憶を持ったまま、更なる未来へ進むことです。","ENG":"What I want is for you to keep moving forward with all your memories.","TWN":"我想要的是妳珍藏所有記憶，繼續朝未來前進。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 당신의 영혼을 차표 삼아 그 운명에 오른 승객일 뿐이죠.","JPN":"私はあなたの魂をチケットの代わりにして、運命に乗り込んだ乗客にすぎない。","ENG":"I am merely a passenger who boarded on your fate using your soul as a ticket.","TWN":"我只是個把你的靈魂當作車票，登上那個命運的乘客。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 선로의 끝에서… 우린 무엇을 마주하게 될까요?","JPN":"その線路の果てで……私たちは何に向き合うのでしょう。","ENG":"And what will we face... at the end of the tracks?","TWN":"在那條軌道的盡頭…我們會面臨什麼呢？"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"대적자, 마왕, 늑대… 그 모든 것을 만들어낸 <color=#ffd34c>원죄</color>","JPN":"敵対者、魔王、オオカミ……そのすべてを生み出した<color=#ffd34c>原罪</color>。","ENG":"The Antagonist, the Demon Lord, the Wolf... and the <color=#ffd34c>original sin</color> that created it all.","TWN":"敵對者、魔王、狼…打造出這一切的<color=#ffd34c>原罪</color>"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"전 수많은 이들과 계약하며 오랜 여행을 거쳐온 끝에, 그 원죄의 이름을 알아냈답니다.","JPN":"沢山の人と契約し、長い間旅を続け……私はその原罪の名がわかりました。","ENG":"After having traveled a long journey and making contracts with countless people, I have discovered the name of the original sin.","TWN":"我在和無數人簽訂契約，經過漫長的旅行後，打探出了那個原罪的名字。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"그 이름은… 탐미엘.","JPN":"その名は……タミエル。","ENG":"That name is... Tammiel.","TWN":"那個名字是…坦米爾。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"It is.","TWN":"沒錯。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그녀 또한 여느 마왕들과 마찬가지로 사도를 부리죠.","JPN":"そして彼女もまた、魔王と同じく使徒を従わせている。","ENG":"And she, too, like many other Demon Lords, has Apostles.","TWN":"而且她也像其他魔王一樣會操縱使徒。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"정말… <color=#ffd34c>그자</color>가 탐미엘의 사도라면…","JPN":"本当に……<color=#ffd34c>あの者</color>がタミエルの使徒なら……","ENG":"If... <color=#ffd34c>she</color> is truly Tammiel's Apostle...","TWN":"如果…<color=#ffd34c>那個人</color>真的是坦米爾的使徒…"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그걸 증명하는 방법은 뭐죠?","JPN":"どうやってそれを証明すればいいのです？","ENG":"...how can you prove that?","TWN":"要怎麼證明這件事？"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그들과 함께하다 보면, 머잖아 알게 될 겁니다.","JPN":"彼らと共にすれば……いずれわかるでしょう。","ENG":"Once you are with them, you will soon find out for yourself.","TWN":"和他們在一起的話，不久後就會知道了。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"세계는 세피로트 나무를 지배하는 마왕 탐미엘에 의해 순환을 거듭하는 것.","JPN":"世界はセフィロトの木を支配する魔王、タミエルによって循環を繰り返す。","ENG":"This world continues its cycle through the Demon Lord Tammiel, the ruler of the Tree of Sephiroth.","TWN":"世界是靠支配生命樹的魔王坦米爾反覆循環。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그 마왕의 사도는 당신처럼 영혼을 팔지 않더라도, 옛 세계의 기억을 온존하는 특별한 존재니까요.","JPN":"魔王の使徒はあなたのように魂を売らずとも、旧世界の記憶を失わない特別な存在ですから。","ENG":"And that Demon Lord's Apostle is a special being who can preserve the memories of the old world, even without selling her soul like you did.","TWN":"那個魔王的使徒是就算不像妳一樣出賣靈魂，也能保存舊世界記憶的特別存在。"},"stage":{"bg":"MS_1302","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"……그렇다면.","JPN":"……それなら。","ENG":"...Then.","TWN":"……那麼，"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 많은 이들 중, 당신이 저를 선택한 이유는 뭐죠?","JPN":"沢山の人の中から、あなたが私を選んだ理由は何ですか？","ENG":"Out of so many candidates, why pick me?","TWN":"在這麼多人當中，你為什麼選擇了我？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"악마에게 영혼을 팔면서까지 이전 세계의 기억을 온존하고.","JPN":"悪魔に魂を売ってまで、旧世界の記憶を保ち……","ENG":"I kept my memories of the old world by selling my soul to a demon.","TWN":"我甚至還把靈魂賣給惡魔，保存先前世界的記憶。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 기억을 통해 제가 거머쥐어야 할 미래는 무엇일까요?","JPN":"その記憶を通して私にどんな未来を掴めというのですか？","ENG":"So what future am I supposed to seize with those memories?","TWN":"我應該透過這段記憶抓住的未來是什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"탐미엘이 규정한 세계의 법칙에서 그녀에게 다다를 수 있는 방법은 하나입니다.","JPN":"タミエルが規定した世界の法則にて、彼女にたどり着く方法はただ1つ。","ENG":"Within the laws of the world as defined by Tammiel, there's only one way to reach her.","TWN":"在坦米爾規定的世界法則中，只有一個能達到她的方法。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"멸망한 세계의 망집으로부터 비롯되어… 그녀가 준비한 무대에서 놀아나는 자들.","JPN":"滅亡した世界への妄執により……彼女が用意した舞台で踊らされる者たち。","ENG":"Born from the delusions of a ruined world, they are the playthings dancing upon the stage she prepared.","TWN":"出於滅亡世界的妄執…在她準備的舞台上被擺布之人。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그래요. 마왕에게 승리하여 세피로트의 나무를 거슬러 올라가는 것이죠.","JPN":"そう、魔王たちに勝利し、セフィロトを遡るのです。","ENG":"Exactly, you defeat the Demon Lord and climb back up the Tree of Sephiroth.","TWN":"沒錯，就是戰勝魔王，沿著生命樹逆行而上。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"한때 전대의 우두머리로서, 또한 관리국의 기술자로서 세계의 진실에 다다른 당신만이.","JPN":"かつて戦隊の長として、そして管理局の技術者として世界の真実に辿り着いたあなたこそが。","ENG":"Only you, a former division commander and engineer of the Administration who grasped the world's truth,","TWN":"妳曾經身為戰隊首領，也是管理局的技師，只有妳達到了世界的真相。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"세계가 탐미엘에게 다다를 분기점 중 하나가 되어줄 겁니다.","JPN":"世界をタミエルに導く分岐点の1つとなってくれるでしょう。","ENG":"can become one of the turning points that lead this world to Tammiel.","TWN":"妳將成為世界到達坦米爾的其中一個分岔點。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"분기점이라면…….","JPN":"分岐点ということは……","ENG":"By turning point...","TWN":"分岔點……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신의 뜻을 따른 들, 세계를 뒤덮는 멸망의 그림자를 피할 수는 없다는 건가요?","JPN":"あなたの言葉に従ったとて、世界を覆う滅亡の影から逃れる術はないということですか？","ENG":"Are you saying that even if I follow your lead, the shadow of apocalypse swallowing the world can't be avoided?","TWN":"意思是聽從妳旨意之人，躲不過籠罩世界的滅亡陰影嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"미래에 일어날 모든 일을 확정 지을 수는 없습니다.","JPN":"無数に枝分かれする未来のすべてを確定づけるなど、到底無理なことです。","ENG":"Not every event in the future can be certain.","TWN":"未來會發生的一切都無法確定。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"하지만 필연적으로 일어날 일에 대해 단편적으로 말씀드리자면…….","JPN":"しかし、必然的に起こるであろうことについて、少しだけお話ししますと……","ENG":"But if I speak in brief about what will inevitably come...","TWN":"但如果要針對必然會發生的事進行片面談論……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"세계의 가능성이 뿌리를 타고 숨겨져 있던 마왕의 이면을 드러내니.","JPN":"世界の可能性が根をたどり、隠れていた魔王の裏面を露わにし。","ENG":"As the world's possibilities climb the roots and bare the hidden face of the Demon Lord...","TWN":"世界的可能性會紮根，而魔王隱藏的底細則會表露。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"마침내, 암군이 옥좌에서 일어나리라.","JPN":"やがて、暗君が玉座から起き上がるであろう。","ENG":"At last, will the Ignorant Monarch rise from the throne.","TWN":"最終，昏君會從寶座上崛起。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"수년 전, 북방합의체 영토권- 시베리아 중부.","JPN":"数年前、北方合意体領土圏 - シベリア中部。","ENG":"Years ago, Northern Union Territory, Central Siberia.","TWN":"L6_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":"L7_1","JPN":"L7_1","ENG":"L7_1","TWN":"L7_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};